//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String homepage;
    String license;
    List<Contributor> contributors;
    String main;
    String types;
    Repository repository;
    Dependencies scripts;
    Dependencies dependencies;
    String typesPublisherContentHash;
    String typeScriptVersion;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.homepage,
        required this.license,
        required this.contributors,
        required this.main,
        required this.types,
        required this.repository,
        required this.scripts,
        required this.dependencies,
        required this.typesPublisherContentHash,
        required this.typeScriptVersion,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        homepage: json["homepage"],
        license: json["license"],
        contributors: List<Contributor>.from(json["contributors"].map((x) => Contributor.fromJson(x))),
        main: json["main"],
        types: json["types"],
        repository: Repository.fromJson(json["repository"]),
        scripts: Dependencies.fromJson(json["scripts"]),
        dependencies: Dependencies.fromJson(json["dependencies"]),
        typesPublisherContentHash: json["typesPublisherContentHash"],
        typeScriptVersion: json["typeScriptVersion"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "homepage": homepage,
        "license": license,
        "contributors": List<dynamic>.from(contributors.map((x) => x.toJson())),
        "main": main,
        "types": types,
        "repository": repository.toJson(),
        "scripts": scripts.toJson(),
        "dependencies": dependencies.toJson(),
        "typesPublisherContentHash": typesPublisherContentHash,
        "typeScriptVersion": typeScriptVersion,
    };
}

class Contributor {
    String name;
    String githubUsername;
    String url;

    Contributor({
        required this.name,
        required this.githubUsername,
        required this.url,
    });

    factory Contributor.fromJson(Map<String, dynamic> json) => Contributor(
        name: json["name"],
        githubUsername: json["githubUsername"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "githubUsername": githubUsername,
        "url": url,
    };
}

class Dependencies {
    Dependencies();

    factory Dependencies.fromJson(Map<String, dynamic> json) => Dependencies(
    );

    Map<String, dynamic> toJson() => {
    };
}

class Repository {
    String type;
    String url;
    String directory;

    Repository({
        required this.type,
        required this.url,
        required this.directory,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
        directory: json["directory"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
        "directory": directory,
    };
}
